  async function handleCheckout(){if(!user){setLoginM(true);return;}const{data,error}=await getSupabase()?.from('orders').insert({buyer_id:user.id,total_amount:cartTotal,shipping_name:checkoutName,shipping_phone:checkoutPhone,shipping_address:checkoutAddr}).select().single();if(error){alert("Error: "+error.message);return;}for(const item of cart){await getSupabase()?.from('order_items').insert({order_id:data.id,product_id:item.id,seller_id:item.seller_id,quantity:item.qty,price:item.price,subtotal:item.price*item.qty});await getSupabase()?.from('products').update({stock:item.stock-item.qty,sold:(item.sold||0)+item.qty}).eq('id',item.id);}setCart([]);setCheckoutAddr("");alert("✅ Pesanan #"+data.id+" berhasil!");fetchP();fetchMO();nav("home");}
