{page==="marketplace"&&!sub&&<div style={{maxWidth:1280,margin:"0 auto",padding:"28px 24px 64px"}}><button className="back" onClick={()=>nav("home")}>← Beranda</button><h1 className="hlg" style={{marginBottom:4}}>🛒 Marketplace</h1><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16,flexWrap:"wrap",gap:8}}><p style={{color:"#aaa",fontSize:13}}>{products.length} produk</p><button className="btn bp bs" onClick={()=>{if(!user){setLoginM(true);return}setShowProductForm(true)}}>➕ Upload Produk</button></div><div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:20,alignItems:"center"}}><div style={{flex:"1 1 220px",position:"relative"}}><span style={{position:"absolute",left:12,top:"50%",transform:"translateY(-50%)",fontSize:13}}>🔍</span><input className="inp" style={{paddingLeft:34,marginBottom:0}} placeholder="Cari produk..." value={mSearch} onChange={e=>setMSearch(e.target.value)}/></div><div style={{display:"flex",gap:4,flexWrap:"wrap"}}>{CATEGORIES.map(c=><button key={c} className={`tab ${mCat===c?"tab-a":""}`} onClick={()=>setMCat(c)}>{c}</button>)}</div></div>{products.length===0?<div style={{textAlign:"center",padding:60,color:"#ccc"}}><div style={{fontSize:48}}>📦</div><p style={{marginTop:10}}>Belum ada produk.</p></div>:<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(240px,1fr))",gap:14}}>{products.filter(p=>(mCat==="Semua"||p.category===mCat)&&p.name.toLowerCase().includes(mSearch.toLowerCase())).map((p,i)=><div key={p.id} className="card" style={{cursor:"pointer",animation:`fadeUp .35s ease ${i*.04}s both`}} onClick={()=>nav("marketplace",p.id)}><div style={{background:`${C.gold}08`,padding:"28px 20px",textAlign:"center",fontSize:52}}>{p.img||"📦"}</div><div style={{padding:"14px 16px"}}><div className="tag" style={{background:`${C.gold}10`,color:C.gold,marginBottom:6}}>{p.category}</div><h4 style={{fontFamily:"'Outfit'",fontWeight:700,fontSize:14,marginBottom:4}}>{p.name}</h4><div style={{fontFamily:"'DM Serif Display'",fontSize:18,color:C.crimson}}>{fmt(p.price)}</div><div style={{fontSize:11,color:"#ccc",marginTop:4}}>🏪 {p.seller?.full_name||"Seller"}</div></div></div>)}</div>}</div>}
{page==="marketplace"&&sub&&(()=>{const p=products.find(x=>x.id===sub);if(!p)return null;return<div style={{maxWidth:960,margin:"0 auto",padding:"28px 24px 64px"}}><button className="back" onClick={()=>nav("marketplace")}>← Marketplace</button><div style={{display:"flex",gap:28,flexWrap:"wrap"}} className="m-col"><div style={{flex:"1 1 300px",background:`${C.gold}06`,borderRadius:18,padding:"48px 32px",textAlign:"center",fontSize:100}}>{p.img||"📦"}</div><div style={{flex:"1 1 340px"}}><h1 style={{fontFamily:"'DM Serif Display'",fontSize:28,marginBottom:6}}>{p.name}</h1><div style={{fontFamily:"'DM Serif Display'",fontSize:32,color:C.crimson,marginBottom:14}}>{fmt(p.price)}</div><p style={{fontSize:13.5,color:"#777",lineHeight:1.7,marginBottom:18}}>{p.description}</p><div style={{padding:"12px 16px",background:"#faf8f5",borderRadius:12,marginBottom:18}}><div style={{fontWeight:700,fontSize:13.5}}>🏪 {p.seller?.full_name}</div><div style={{fontSize:11.5,color:"#aaa"}}>📍 {p.seller?.city} · Stok: {p.stock}</div></div><div style={{display:"flex",gap:10,flexWrap:"wrap"}}><button className="btn bp" style={{flex:1}} onClick={()=>{addCart(p);setCartOpen(true)}}>🛒 Keranjang</button><button className="btn" style={{background:"#25D366",color:"white",padding:"12px 20px",borderRadius:50}} onClick={()=>window.open(`https://wa.me/${p.seller?.phone||"628xx"}?text=Halo, saya tertarik dengan ${p.name}`)}>💬 Chat WA</button></div></div></div></div>})()}

