{page==="elearning"&&!sub&&<div style={{maxWidth:1280,margin:"0 auto",padding:"28px 24px 64px"}}><button className="back" onClick={()=>nav("home")}>← Beranda</button><h1 className="hlg" style={{marginBottom:4}}>📚 E-Learning</h1><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16,flexWrap:"wrap",gap:8}}><p style={{color:"#aaa",fontSize:13}}>{courses.length} kursus</p><button className="btn bp bs" onClick={()=>{if(!user){setLoginM(true);return}setShowCourseForm(true)}}>➕ Buat Kursus</button></div>{courses.length===0?<div style={{textAlign:"center",padding:60,color:"#ccc"}}><div style={{fontSize:48}}>📚</div><p style={{marginTop:10}}>Belum ada kursus.</p></div>:<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:16}}>{courses.map((c,i)=><div key={c.id} className="card" style={{cursor:"pointer"}} onClick={()=>nav("elearning",c.id)}><div style={{background:`${C.crimson}06`,padding:"28px 20px",textAlign:"center",fontSize:52}}>📚</div><div style={{padding:"16px 18px"}}><h4 style={{fontFamily:"'Outfit'",fontWeight:700,fontSize:15,marginBottom:6}}>{c.title}</h4><div style={{fontSize:12,color:"#999",marginBottom:8}}>👨‍🏫 {c.instructor?.full_name} · {c.level}</div><div style={{fontSize:12,color:"#bbb"}}>{c.course_modules?.length||0} materi · {c.course_quizzes?.length||0} quiz</div><div style={{marginTop:10,fontWeight:700,fontSize:13,color:C.crimson}}>Mulai →</div></div></div>)}</div>}</div>}
{page==="elearning"&&sub&&(()=>{const c=courses.find(x=>x.id===sub);if(!c)return null;const ms=c.course_modules||[],qz=c.course_quizzes||[],qs=qz.length?Object.keys(quizAnswers).filter(k=>quizAnswers[k]===qz[k]?.correct_answer).length:0;return<div style={{maxWidth:960,margin:"0 auto",padding:"28px 24px 64px"}}><button className="back" onClick={()=>nav("elearning")}>← Kursus</button><div style={{display:"flex",gap:24,flexWrap:"wrap"}} className="m-col"><div style={{flex:"0 0 260px",minWidth:240}}><div className="card" style={{padding:18}}><h3 style={{fontFamily:"'Outfit'",fontWeight:800,fontSize:16,marginBottom:6}}>{c.title}</h3><div style={{fontSize:12,color:"#999",marginBottom:10}}>👨‍🏫 {c.instructor?.full_name}</div><div style={{borderTop:"1px solid #f0ece6",paddingTop:12}}>{ms.map((m,i)=><div key={m.id} onClick={()=>{setActiveLesson(i);setQuizStarted(false);setQuizDone(false)}} style={{padding:"8px 10px",borderRadius:8,marginBottom:4,cursor:"pointer",fontSize:12.5,fontWeight:activeLesson===i&&!quizStarted?700:500,background:activeLesson===i&&!quizStarted?`${C.crimson}10`:"transparent",color:activeLesson===i&&!quizStarted?C.crimson:"#777"}}>{m.type==="video"?"🎬":"📄"} {m.title}</div>)}{qz.length>0&&<div onClick={()=>{setQuizStarted(true);setQuizDone(false);setQuizAnswers({})}} style={{padding:"8px 10px",borderRadius:8,marginTop:4,cursor:"pointer",fontSize:12.5,fontWeight:quizStarted?700:500,background:quizStarted?`${C.emerald}10`:"transparent",color:quizStarted?C.emerald:"#777"}}>📝 Quiz ({qz.length})</div>}</div></div></div><div style={{flex:1,minWidth:0}}>{!quizStarted&&ms[activeLesson]?<div className="card" style={{padding:24}}><h3 className="hmd" style={{marginBottom:6}}>{ms[activeLesson].title}</h3><div style={{fontSize:12,color:"#aaa",marginBottom:14}}>{ms[activeLesson].type==="video"?"Video":"Artikel"}</div>{ms[activeLesson].type==="video"&&<div style={{background:"#1a1a2e",borderRadius:14,padding:"48px 20px",textAlign:"center",marginBottom:16}}><div style={{width:64,height:64,borderRadius:50,background:"rgba(255,255,255,.15)",display:"inline-flex",alignItems:"center",justifyContent:"center",fontSize:28,cursor:"pointer"}}>▶</div></div>}<div style={{fontSize:14,lineHeight:1.8,color:"#555",whiteSpace:"pre-wrap"}}>{ms[activeLesson].content}</div><button className="btn" style={{width:"100%",marginTop:16,background:C.emerald,color:"white",padding:"12px 20px",fontSize:13}} onClick={()=>handleMarkComplete(c.id,ms[activeLesson].id)}>✅ Tandai Selesai</button><div style={{display:"flex",justifyContent:"space-between",marginTop:12}}><button className="btn bo bs" disabled={activeLesson===0} onClick={()=>setActiveLesson(p=>p-1)}>←</button>{activeLesson<ms.length-1?<button className="btn bp bs" onClick={()=>setActiveLesson(p=>p+1)}>→</button>:qz.length>0&&<button className="btn bp bs" style={{background:C.emerald}} onClick={()=>{setQuizStarted(true);setQuizDone(false);setQuizAnswers({})}}>Quiz →</button>}</div></div>:quizStarted&&<div className="card" style={{padding:24}}>{!quizDone?<>{qz.map((q,qi)=><div key={qi} style={{marginBottom:18,padding:16,background:"#faf8f5",borderRadius:12}}><div style={{fontWeight:700,fontSize:13.5,marginBottom:10}}>{qi+1}. {q.question}</div>{(q.options||[]).map((o,oi)=><div key={oi} onClick={()=>setQuizAnswers(p=>({...p,[qi]:oi}))} style={{padding:"10px 14px",borderRadius:8,marginBottom:5,cursor:"pointer",border:`2px solid ${quizAnswers[qi]===oi?C.crimson:"#eee"}`,background:quizAnswers[qi]===oi?`${C.crimson}08`:"white",fontSize:13}}>{String.fromCharCode(65+oi)}. {o}</div>)}</div>)}<button className="btn bp" style={{width:"100%"}} onClick={()=>handleSubmitQuiz(c.id,qz)}>Selesai</button></>:<div style={{textAlign:"center",padding:"20px 0"}}><div style={{fontSize:56,marginBottom:10}}>{qs>=qz.length*0.7?"🏆":"📋"}</div><h3 className="hlg">Skor: {qs}/{qz.length}</h3><div style={{fontSize:14,color:qs>=qz.length*0.7?C.emerald:C.copper,fontWeight:700,marginTop:6}}>{qs>=qz.length*0.7?"Lulus! Sertifikat tersimpan.":"Belum lulus."}</div><button className="btn bp" style={{marginTop:16}} onClick={()=>nav("elearning")}>Kembali</button></div>}</div>}</div></div></div>})()}

