{hibahReq!==null&&<div className="modal-bg" onClick={()=>setHibahReq(null)}><div className="modal" onClick={e=>e.stopPropagation()}><button onClick={()=>setHibahReq(null)} style={{position:"absolute",top:12,right:16,background:"none",border:"none",fontSize:17,cursor:"pointer",color:"#ccc"}}>✕</button><h3 className="hmd" style={{marginBottom:12}}>Ajukan Hibah</h3><textarea className="inp" placeholder="Alasan..." style={{minHeight:80}} value={hibahReason} onChange={e=>setHibahReason(e.target.value)}/><button className="btn bp" style={{width:"100%"}} onClick={()=>handleHibahRequest(hibahReq)}>Kirim</button></div></div>}
